external_knowledge:
- 'Garden's vibrant flowers' refers to active users; 
- 'wilted away' serves as a metaphor for users who haven't accessed the platform after a specific date; 
- 'bloom under the sun's rays' symbolizes accessing the platform; 
- 'after May 1, 2023' represents the cutoff date for access activity. ;
- Active users are those with 'is_active' equal to 1. ;

sql:
SELECT number_type, COUNT(*) as request_count
FROM generation_requests
GROUP BY number_type;

SELECT generator_name
FROM generators
WHERE is_active = 1;

SELECT request_id
FROM generation_requests
WHERE number_type = 'real' AND num_of_numbers > 1;

SELECT COUNT(DISTINCT user_id) AS number_of_unique_users
FROM generation_requests
WHERE created_at BETWEEN '2022-01-01' AND '2022-12-31';

SELECT COUNT(DISTINCT user_id), AVG(generated_number)
FROM generation_results
WHERE generated_number > 90;

SELECT * 
FROM generators 
WHERE generator_id = 1;

SELECT generator_id, algorithm 
FROM generators 
WHERE is_active = 1;

SELECT g.generator_name, r.user_id, r.status
FROM generators g
INNER JOIN generation_requests r ON g.generator_id = r.generator_id;

SELECT DISTINCT u.username 
FROM users u 
INNER JOIN generation_requests g ON u.user_id = g.user_id;

SELECT CAST(AVG(mean) AS TEXT) AS MeanOfMeans
FROM analytics
WHERE request_id != 0;
